import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import FloatingInput from "../component/FloatingInput";

export default function AdminCreateUser() {
  const navigate = useNavigate();

  const [user, setUser] = useState({
    username: "",
    name: "",
    email: "",
    password: "",
    role: "Student",
  });

  const [errors, setErrors] = useState({});
  const [success, setSuccess] = useState("");

  const BASE_URL = "http://localhost:8086";

  const handleChange = (e) => {
    setUser({
      ...user,
      [e.target.name]: e.target.value,
    });

    setErrors({
      ...errors,
      [e.target.name]: "",
    });
  };

  const validate = () => {
    const err = {};

    if (!user.username) err.username = "Username is required";
    if (!user.name) err.name = "Full name is required";

    if (!user.email) {
      err.email = "Email is required";
    } else if (user.role === "Student") {
      if (!/^[iI][tT]\d{8}@my\.sliit\.lk$/.test(user.email)) {
        err.email = "Use ITXXXXXXXX@my.sliit.lk format";
      }
    }

    if (!user.password) {
      err.password = "Password is required";
    } else if (user.password.length < 6) {
      err.password = "Minimum 6 characters required";
    }

    return err;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    setErrors({});
    setSuccess("");

    const validationErrors = validate();
    if (Object.keys(validationErrors).length > 0) {
      setErrors(validationErrors);
      return;
    }

    try {
      const response = await fetch(`${BASE_URL}/user/admin/create`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(user),
      });

      if (response.ok) {
        setSuccess("User created successfully 🎉");

        setUser({
          username: "",
          name: "",
          email: "",
          password: "",
          role: "Student",
        });

        setTimeout(() => {
          navigate("/admin/users");
        }, 1200);
      } else {
        setErrors({ submit: "Failed to create user" });
      }
    } catch {
      setErrors({ submit: "Server not responding" });
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-gray-900 via-gray-800 to-black relative overflow-hidden">

      {/* BACKDROP BLUR OVERLAY */}
      <div className="absolute inset-0 bg-black/40 backdrop-blur-sm"></div>

      {/* CARD */}
      <div className="relative w-[520px] p-8 rounded-2xl bg-white/10 backdrop-blur-xl border border-white/20 shadow-2xl z-10">

        {/* TITLE */}
        <h2 className="text-2xl font-bold text-white text-center mb-6">
          Admin Create User
        </h2>

        {/* SUCCESS MESSAGE */}
        {success && (
          <p className="text-green-300 text-center mb-3 font-medium">
            {success}
          </p>
        )}

        {/* ERROR MESSAGE */}
        {errors.submit && (
          <p className="text-red-300 text-center mb-3 font-medium">
            {errors.submit}
          </p>
        )}

        {/* FORM */}
        <form onSubmit={handleSubmit} className="space-y-4">

          <FloatingInput
            name="username"
            label="Username"
            value={user.username}
            onChange={handleChange}
          />
          {errors.username && <p className="text-red-300 text-sm">{errors.username}</p>}

          <FloatingInput
            name="name"
            label="Full Name"
            value={user.name}
            onChange={handleChange}
          />
          {errors.name && <p className="text-red-300 text-sm">{errors.name}</p>}

          <FloatingInput
            name="email"
            type="email"
            label="Email"
            value={user.email}
            onChange={handleChange}
          />
          {errors.email && <p className="text-red-300 text-sm">{errors.email}</p>}

          <FloatingInput
            name="password"
            type="password"
            label="Password"
            value={user.password}
            onChange={handleChange}
          />
          {errors.password && <p className="text-red-300 text-sm">{errors.password}</p>}

          {/* ROLE */}
          <div>
            <label className="text-white text-sm mb-1 block">Role</label>
            <select
              name="role"
              value={user.role}
              onChange={handleChange}
              className="w-full px-4 py-3 rounded-lg bg-white/10 border border-white/20 text-white backdrop-blur-md focus:outline-none focus:ring-2 focus:ring-indigo-400"
            >
              <option className="text-black" value="Student">Student</option>
              <option className="text-black" value="Admin">Admin</option>
              <option className="text-black" value="Academic Panel">Academic Panel</option>
            </select>
          </div>

          {/* BUTTON */}
          <button
            type="submit"
            className="w-full py-2 rounded-lg bg-indigo-500/70 hover:bg-indigo-500 text-white font-semibold transition-all duration-200"
          >
            Create User
          </button>

          {/* CANCEL */}
          <button
            type="button"
            onClick={() => navigate("/admin/users")}
            className="w-full py-2 rounded-lg bg-white/10 hover:bg-white/20 text-white border border-white/20 transition"
          >
            Cancel
          </button>

        </form>
      </div>
    </div>
  );
}
